// QuerySeriesProvider queries the series_provider edge of a ProviderChapter.
func (c *ProviderChapterClient) QuerySeriesProvider(_m *ProviderChapter) *SeriesProviderQuery {
	query := (&SeriesProviderClient{config: c.config}).Query()
	query.path = func(context.Context) (fromV *sql.Selector, _ error) {
		id := _m.ID
		step := sqlgraph.NewStep(
			sqlgraph.From(providerchapter.Table, providerchapter.FieldID, id),
			sqlgraph.To(seriesprovider.Table, seriesprovider.FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, providerchapter.SeriesProviderTable, providerchapter.SeriesProviderColumn),
		)
		fromV = sqlgraph.Neighbors(_m.driver.Dialect(), step)
		return fromV, nil
	}
	return query
}

