// QuerySeriesProvider queries the series_provider edge of a SuwayomiSyncState.
func (c *SuwayomiSyncStateClient) QuerySeriesProvider(_m *SuwayomiSyncState) *SeriesProviderQuery {
	query := (&SeriesProviderClient{config: c.config}).Query()
	query.path = func(context.Context) (fromV *sql.Selector, _ error) {
		id := _m.ID
		step := sqlgraph.NewStep(
			sqlgraph.From(suwayomisyncstate.Table, suwayomisyncstate.FieldID, id),
			sqlgraph.To(seriesprovider.Table, seriesprovider.FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, suwayomisyncstate.SeriesProviderTable, suwayomisyncstate.SeriesProviderColumn),
		)
		fromV = sqlgraph.Neighbors(_m.driver.Dialect(), step)
		return fromV, nil
	}
	return query
}

